const repo = $input.first().json.gh_repo;
const keywords = $input.first().json.keywords;

const chunks = [];
for (let i = 0; i < keywords.length; i += 5) {
  chunks.push(keywords.slice(i, i + 5));
}

return chunks.map(chunk => ({
  query: `repo:${repo} type:pr is:open in:title (${chunk.join(' OR ')})`,
  repo_owner: repo.split('/')[0],
  repo_name: repo.split('/')[1],
  keywords: keywords
}));

const all_responses = $input.all();
const pr_numbers = new Set();
const prs = [];
const keywords = all_responses[0]?.json?.keywords || [];

for (const response of all_responses) {
  const items = response.json.items || [];
  for (const item of items) {
    const title = item.title || "";
    if (title.toLowerCase().includes("[backport")) {
      continue;
    }

    if (!pr_numbers.has(item.number)) {
      pr_numbers.add(item.number);
      prs.push(item);
    }
  }
}

return {
  pr_numbers: Array.from(pr_numbers),
  prs: prs,
  keywords: keywords
};

const all_items = $input.all();
const cached_item = all_items[0]?.json?.data?.[0] || {};
const cur = all_items[1]?.json || {};

const pr_numbers_prev = cached_item.pr_numbers || [];
const pr_numbers_cur = cur.pr_numbers || [];
const pr_numbers_diff = pr_numbers_cur.filter(x => !pr_numbers_prev.includes(x));

const new_prs_data = (cur.prs || []).filter(x => pr_numbers_diff.includes(x.number));

return {
  pr_numbers: {
    prev: pr_numbers_prev,
    cur: pr_numbers_cur,
    diff: pr_numbers_diff
  },
  prs: new_prs_data,
  keywords: cur.keywords
};

const item = $input.first().json;
const new_prs = item.prs || [];
if (new_prs.length === 0) return [];

const keywords = item.keywords || [];
const workflowId = $workflow.id;
const workflowName = $workflow.name;
const executionId = $execution.id;

const escapeHtml = (unsafe) => {
  return (unsafe || "").toString()
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
};

const formatDate = (isoString) => {
  if (!isoString) return "N/A";
  const date = new Date(isoString);
  return date.toLocaleDateString('en-US', { 
    month: 'short', 
    day: 'numeric', 
    year: 'numeric' 
  });
};

let html_body = `
<!DOCTYPE html>
<html>
<head>
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <style>
    body { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Helvetica, Arial, sans-serif; line-height: 1.5; color: #24292f; background-color: #f6f8fa; margin: 0; padding: 10px; }
    .container { max-width: 600px; margin: 0 auto; background-color: #ffffff; border: 1px solid #d0d7de; border-radius: 6px; overflow: hidden; }
    .header { padding: 16px 20px; background-color: #24292f; color: #ffffff; }
    .header h1 { margin: 0; font-size: 18px; font-weight: 600; }
    .content { padding: 20px; }
    .pr-item { padding-bottom: 16px; margin-bottom: 16px; border-bottom: 1px solid #d0d7de; }
    .pr-item:last-child { border-bottom: none; margin-bottom: 0; padding-bottom: 0; }
    .pr-title { font-size: 16px; font-weight: 600; color: #0969da; text-decoration: none; display: block; margin-bottom: 6px; word-break: break-word; }
    .pr-title:hover { text-decoration: underline; }
    .pr-meta { font-size: 12px; color: #57606a; display: block; }
    .status-open { color: #1a7f37; font-weight: 600; margin-right: 8px; }
    .footer { padding: 16px 20px; background-color: #f6f8fa; border-top: 1px solid #d0d7de; font-size: 12px; color: #57606a; }
    .keywords { margin-top: 8px; margin-bottom: 16px; }
    .keyword-tag { background-color: #ddf4ff; color: #0969da; padding: 2px 8px; border-radius: 12px; font-weight: 500; display: inline-block; margin: 2px; }
    .debug-links { border-top: 1px solid #d0d7de; padding-top: 12px; margin-top: 12px; }
    .debug-links a { color: #0969da; text-decoration: none; margin-right: 12px; }

    @media (max-width: 480px) {
      body { padding: 5px; }
      .header h1 { font-size: 16px; }
      .content { padding: 15px; }
      .pr-title { font-size: 15px; }
    }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>📮 GitHub nixpkgs PR Digest</h1>
    </div>
    <div class="content">
`;

for (const pr of new_prs) {
  const title = escapeHtml(pr.title);
  const url = pr.html_url || "#";
  const date = formatDate(pr.created_at);
  const number = pr.number;
  const user = pr.user?.login || "unknown";

  html_body += `
      <div class="pr-item">
        <a href="${url}" class="pr-title">${title} #${number}</a>
        <div class="pr-meta">
          <span class="status-open">⊙ Open</span> <span>by <strong>${user}</strong></span>
          <span style="margin-left: 8px;">on ${date}</span>
        </div>
      </div>
  `;
}

html_body += `
    </div>
    <div class="footer">
      <div style="font-weight: 600; margin-bottom: 4px;">Active Keywords:</div>
      <div class="keywords">
        ${keywords.map(kw => `<span class="keyword-tag">${escapeHtml(kw)}</span>`).join('')}
      </div>
      <div class="debug-links">
        <div style="margin-bottom: 8px; font-weight: 600;">${escapeHtml(workflowName)}</div>
        <a href="https://n8n.brkn.lol/workflow/${workflowId}">📝 Edit Workflow</a>
        <a href="https://n8n.brkn.lol/workflow/${workflowId}/executions/${executionId}">🔍 View Execution</a>
      </div>
      <p style="margin-top: 16px; font-style: italic; opacity: 0.8;">Automated digest from n8n.brkn.lol</p>
    </div>
  </div>
</body>
</html>
`;

let text_body = "New Open PRs from nixos/nixpkgs matching your keywords:\n\n";
for (const pr of new_prs) {
  text_body += `[${pr.title}] #${pr.number}\nURL: ${pr.html_url}\nBy: ${pr.user?.login} on ${pr.created_at}\n\n`;
}
text_body += "\nActive Keywords: " + keywords.join(", ");
text_body += `\n\nWorkflow: ${workflowName}`;
text_body += `\nEdit Workflow: https://n8n.brkn.lol/workflow/${workflowId}`;
text_body += `\nView Execution: https://n8n.brkn.lol/workflow/${workflowId}/executions/${executionId}`;

return {
  emailBodyHtml: html_body,
  emailBodyText: text_body
};

